import numpy as np
from sklearn.metrics import confusion_matrix

def disparity_report(y_true, y_pred, group):
    """Compute key disparity metrics across two groups (0 and 1)."""
    results = {}
    for g in [0, 1]:
        mask = group == g
        yt, yp = y_true[mask], y_pred[mask]
        tn, fp, fn, tp = confusion_matrix(yt, yp, labels=[0, 1]).ravel()
        results[g] = {
            'positive_rate': (tp + fp) / len(yt),
            'tpr': tp / (tp + fn) if (tp + fn) > 0 else 0,  # recall
            'fpr': fp / (fp + tn) if (fp + tn) > 0 else 0,
            'ppv': tp / (tp + fp) if (tp + fp) > 0 else 0,  # precision
        }
    gaps = {k: abs(results[0][k] - results[1][k]) for k in results[0]}
    return results, gaps

